func svcJSON(ports ...corev1api.ServicePort) string {
	svc := corev1api.Service{
		Spec: corev1api.ServiceSpec{
			HealthCheckNodePort: 8080,
			Ports:               ports,
		},
	}

	data, err := json.Marshal(svc)
